mapper.select:
SELECT p.id, p.name, p.description, p.price, p.stock, p.image_url, p.product_category_id AS category_id, pc.name AS category_name, p.rating, p.review_count, COALESCE(CAST(ROUND(CAST(NULLIF(f.calories, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0) AS SIGNED), 0) AS calories, COALESCE(CAST(ROUND(CAST(NULLIF(f.protein, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0) AS SIGNED), 0) AS protein, COALESCE(CAST(ROUND(CAST(NULLIF(f.carbs, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0) AS SIGNED), 0) AS carbs, COALESCE(CAST(ROUND(CAST(NULLIF(f.fat, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0) AS SIGNED), 0) AS fat FROM products p LEFT JOIN product_categories pc ON p.product_category_id = pc.id LEFT JOIN food f ON p.food_id = f.id WHERE p.deleted_date IS NULL
AND p.product_category_id = #{categoryId}
AND ( p.name LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR p.description LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR pc.name LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR f.name LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR CAST(COALESCE(ROUND(CAST(NULLIF(f.calories, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0), 0) AS CHAR) LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR CAST(COALESCE(ROUND(CAST(NULLIF(f.protein, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0), 0) AS CHAR) LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR CAST(COALESCE(ROUND(CAST(NULLIF(f.carbs, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0), 0) AS CHAR) LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR CAST(COALESCE(ROUND(CAST(NULLIF(f.fat, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0), 0) AS CHAR) LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' )
ORDER BY p.created_date DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM products p LEFT JOIN product_categories pc ON p.product_category_id = pc.id LEFT JOIN food f ON p.food_id = f.id WHERE p.deleted_date IS NULL
AND p.product_category_id = #{categoryId}
AND ( p.name LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR p.description LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR pc.name LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR f.name LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR CAST(COALESCE(ROUND(CAST(NULLIF(f.calories, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0), 0) AS CHAR) LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR CAST(COALESCE(ROUND(CAST(NULLIF(f.protein, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0), 0) AS CHAR) LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR CAST(COALESCE(ROUND(CAST(NULLIF(f.carbs, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0), 0) AS CHAR) LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' OR CAST(COALESCE(ROUND(CAST(NULLIF(f.fat, '') AS DECIMAL(10,2)) * p.weight_g / 100, 0), 0) AS CHAR) LIKE CONCAT('%', #{escapedKeyword}, '%') ESCAPE '\\' )

SELECT COUNT(*) > 0
FROM products
WHERE id = #{productId}
  AND user_id = #{userId}
  AND deleted_date IS NULL

mapper.update:
UPDATE products
SET stock = stock - #{quantity}
WHERE id = #{productId}
  AND stock >= #{quantity}
  AND deleted_date IS NULL

UPDATE products
SET stock = stock + #{quantity}
WHERE id = #{productId}
  AND deleted_date IS NULL
